import { useNavigate, useOutletContext } from "react-router";
import { motion } from "framer-motion";

import { Card, CardBody, CardFooter } from "@nextui-org/react";

import ImageCustom from "../../components/ImageCustom";
import ButtonAddCart from "../../components/ButtonAddCart";
import PriceLabel from "../../components/PriceLabel";

export default function ItemsView({
  items = [],
  showMoreItems = () => {},
  totalItems = 0,
}) {
  const context = useOutletContext();
  const navigate = useNavigate();

  const cart = context.cart.value;

  return (
    <section className="w-full grid grid-cols-1 xs:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-4 sm:gap-8 md:gap-10">
      {items.map((item) => (
        <motion.div
          key={item.id}
          className="relative"
          initial={{ opacity: 0, scale: 1.5 }}
          whileInView={{ opacity: 1, scale: 1 }}
        >
          <ButtonAddCart
            inCart={item.id in cart}
            itemData={item}
            handleAdd={context.cart.add}
            className="absolute top-2 z-20 right-2"
          />

          <Card
            isPressable
            className="w-full h-full hover:scale-105"
            onPress={() => navigate(`/search/${item.id}`)}
          >
            <CardBody className="overflow-visible p-0">
              {item?.svg ? (
                <div className="shadow-small rounded-lg p-4 self-center h-[200px] w-full">
                  <item.svg className="h-full w-full" />
                </div>
              ) : (
                <ImageCustom
                  alt={`Imagen de ${item.label}`}
                  className="w-full object-contain p-4 h-[200px] rounded-lg shadow-small"
                  src={item?.img}
                  width="100%"
                />
              )}
            </CardBody>

            <CardFooter className="flex-col items-start h-full">
              <p className="text-second self-start text-neutral-400 capitalize line-clamp-1">
                {item.categorie} {item?.subcategorie || ""}
              </p>
              <b className="line-clamp-1 text-start">{item.label}</b>
              <PriceLabel
                itemData={item}
                className="self-end"
                classNames={{
                  price:
                    "text-custom2 dark:text-custom1 font-semibold text-tertiary",
                }}
              />
            </CardFooter>
          </Card>
        </motion.div>
      ))}

      {items.length < totalItems && (
        <Card
          isPressable
          shadow="sm"
          className="bg-warning-300 "
          onPress={showMoreItems}
        >
          <CardBody className="overflow-visible p-0">
            <ImageCustom
              alt={"alt"}
              className="w-full object-cover h-[140px]"
              radius="lg"
              shadow="sm"
              src={null}
              width="100%"
            />
          </CardBody>

          <CardFooter className="items-center justify-center h-full">
            <b>Cargar mas</b>
          </CardFooter>
        </Card>
      )}
    </section>
  );
}
